import React, { useState } from 'react';
import './App.css';

function App() {
  const [inputText, setInputText] = useState('hello, how are you');
  const [encodedNumber, setEncodedNumber] = useState('');
  const [ratio, setRatio] = useState(null);
  const [a, setA] = useState(0);
  const [b, setB] = useState(0);

  const encodeText = (text) => {
    // Convert to lowercase and replace non-alphabetic characters with spaces
    const cleaned = text.toLowerCase().replace(/[^a-z]/g, ' ');

    let encoded = '';
    for (let char of cleaned) {
      if (char === ' ') {
        encoded += '00';
      } else {
        const charCode = char.charCodeAt(0) - 96; // 'a' is 97 in ASCII
        encoded += charCode.toString().padStart(2, '0');
      }
    }

    return encoded;
  };

  const findRatio = (decimal) => {
    // Find A and B such that A/B = decimal
    // We'll use continued fractions to find a good approximation

    const tolerance = 1e-10;
    let h1 = 1, h2 = 0;
    let k1 = 0, k2 = 1;
    let x = decimal;

    while (true) {
      const a = Math.floor(x);
      let h = a * h1 + h2;
      let k = a * k1 + k2;

      const ratio = h / k;
      if (Math.abs(ratio - decimal) < tolerance) {
        return { a: h, b: k, ratio: ratio };
      }

      if (k > 10000) break; // Prevent infinite loops with very precise decimals

      h2 = h1;
      h1 = h;
      k2 = k1;
      k1 = k;

      if (x === a) break;
      x = 1 / (x - a);
    }

    return { a: h1, b: k1, ratio: h1 / k1 };
  };

  const handleEncode = () => {
    const encoded = encodeText(inputText);
    setEncodedNumber(encoded);

    // Convert to decimal by prefixing with "0."
    const decimal = parseFloat('0.' + encoded);

    // Find A and B
    const ratioResult = findRatio(decimal);
    setRatio(ratioResult.ratio);
    setA(ratioResult.a);
    setB(ratioResult.b);
  };

  const totalLength = a + b;
  const aPercentage = (a / totalLength) * 100;

  return (
    <div className="App">
      <div className="container">
        <h1>Message Encoder</h1>

        <div className="input-section">
          <label htmlFor="message">Enter your message:</label>
          <input
            id="message"
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Enter your message..."
          />
          <button onClick={handleEncode}>Encode</button>
        </div>

        {encodedNumber && (
          <div className="results">
            <div className="result-section">
              <h3>Encoded Number:</h3>
              <p className="encoded-number">{encodedNumber}</p>
            </div>

            <div className="result-section">
              <h3>Decimal Ratio:</h3>
              <p>0.{encodedNumber} ≈ {ratio?.toFixed(10)}</p>
            </div>

            <div className="result-section">
              <h3>Division Values:</h3>
              <p>A = {a}</p>
              <p>B = {b}</p>
              <p>A/B = {(a/b).toFixed(10)}</p>
            </div>

            <div className="visualization">
              <h3>Wooden Plank Visualization:</h3>
              <div className="plank-container">
                <div className="plank">
                  <div
                    className="section-a"
                    style={{ width: `${aPercentage}%` }}
                  >
                    <span className="label">A ({a})</span>
                  </div>
                  <div
                    className="section-b"
                    style={{ width: `${100 - aPercentage}%` }}
                  >
                    <span className="label">B ({b})</span>
                  </div>
                </div>
                <div className="plank-info">
                  Total Length: {totalLength} units
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
